// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "./Ownable.sol";

abstract contract CandidateRegistry is Ownable {
    // 1. Структура кандидата
    struct Candidate {
        uint id;
        string name;
        uint votes;
    }

    // 2. Динамічний масив для зберігання всіх кандидатів
    Candidate[] public candidates;

    // 3. Подія, яка викликається при додаванні нового кандидата
    event CandidateAdded(uint id, string name);

    // 4. Внутрішня (internal) функція для додавання кандидата
    // Вона доступна тільки всередині цього контракту та його нащадків
    function addCandidate(string memory name) internal {
        uint newId = candidates.length; // ID дорівнює поточному індексу в масиві

        // Створюємо та додаємо нового кандидата (початкові голоси = 0)
        candidates.push(Candidate(newId, name, 0));

        // Генеруємо подію додавання
        emit CandidateAdded(newId, name);
    }

    // 5. Внутрішня функція для збільшення кількості голосів кандидата
    function voteCandidate(uint id) internal {
        // Перевіряємо, що такий кандидат взагалі існує в масиві
        require(id < candidates.length, "Candidate does not exist");
        candidates[id].votes++;
    }

    // 6. Публічна функція для отримання інформації про кандидата за його ID
    function getCandidate(uint id) external view returns (uint, string memory, uint) {
        require(id < candidates.length, "Candidate does not exist");
        Candidate memory c = candidates[id];
        return (c.id, c.name, c.votes);
    }

    // 7. Публічна функція, що повертає загальну кількість кандидатів
    function totalCandidates() external view returns (uint) {
        return candidates.length;
    }
}

contracts/Ownable.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28; // Використовуємо версію як у вашому Counter.sol

abstract contract Ownable {
    // 1. Змінна для зберігання адреси власника
    address public owner;

    // 2. Подія, яка спрацьовує при зміні або встановленні власника
    event OwnerChanged(address indexed oldOwner, address indexed newOwner);

    // 3. Конструктор встановлює першого власника (того, хто робить деплой)
    constructor() {
        owner = msg.sender;
        emit OwnerChanged(address(0), msg.sender);
    }

    // 4. Модифікатор, який обмежує доступ до функцій (лише для owner)
    modifier onlyOwner() {
        require(msg.sender == owner, "Not an owner");
        _;
    }
}
